using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: Discriminator property renamed from "Discriminator" to "$type".
        // Keep the old name so existing documents remain readable and raw SQL
        // queries filtering on c.Discriminator continue to work.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id no longer includes the discriminator prefix.
        // Keep the old "Blog|1" format so existing documents are still found.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex now throws for Cosmos entities.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
        // Manage indexing via the Cosmos DB indexing policy instead.
    }
}
